import React, { useState } from "react";
import { motion } from "framer-motion";

const ExploreHeritage = () => {

  // ✅ State for search input
  const [search, setSearch] = useState("");

  // ✅ State for category dropdown
  const [selectedCategory, setSelectedCategory] = useState("All");

  // ✅ Sample Data (Later replace with API data)
  const memoriesData = [
    {
      id: 1,
      title: "Bastar Dussehra",
      description: "A 75-day long traditional festival celebrated in Bastar.",
      category: "Festivals",
      location: "Bastar",
      image: "data:image/jpeg;base64,"
    },
    {
      id: 2,
      title: "Panthi Dance",
      description: "A vibrant folk dance performed by the Satnami community.",
      category: "Folk Dance",
      location: "Raipur",
      image: "data:image/jpeg;base64,"
    },
    {
      id: 3,
      title: "Chila - Traditional Food",
      description: "A delicious rice-based dish loved across Chhattisgarh.",
      category: "Traditional Food",
      location: "Bilaspur",
      image: "data:image/jpeg;base64,"
    }
  ];

  const filteredMemories = memoriesData.filter((memory) => {
    return (
      (selectedCategory === "All" || memory.category === selectedCategory) &&
      memory.title.toLowerCase().includes(search.toLowerCase())
    );
  });

  return (
    <div className="bg-[#F7F1E1] min-h-screen px-6 py-12">

      {/* Page Heading */}
      <div className="text-center mb-10">
        <h1 className="text-4xl font-serif text-[#8B2E1F] mb-3">
          Explore Heritage
        </h1>
        <p className="text-gray-600 max-w-xl mx-auto">
          Discover stories, traditions and memories shared by our community.
        </p>
      </div>

      {/* Search + Filter Section */}
      <div className="flex flex-col md:flex-row gap-4 justify-center mb-12">

        {/* Search Input */}
        <input
          type="text"
          placeholder="Search memories..."
          className="px-4 py-2 rounded-lg border focus:outline-none focus:ring-2 focus:ring-[#E0B84C] w-full md:w-1/3"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        {/* Category Dropdown */}
        <select
          className="px-4 py-2 rounded-lg border focus:outline-none focus:ring-2 focus:ring-[#E0B84C] w-full md:w-1/4"
          value={selectedCategory}
          onChange={(e) => setSelectedCategory(e.target.value)}
        >
          <option value="All">All</option>
          <option value="Festivals">Festivals</option>
          <option value="Folk Dance">Folk Dance</option>
          <option value="Traditional Food">Traditional Food</option>
        </select>
      </div>

      {/* Memory Cards Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">

        {filteredMemories.map((memory) => (
          <motion.div
            key={memory.id}
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-xl hover:-translate-y-2 transition-all duration-300"
          >

            {/* Image */}
            <img
              src={memory.image}
              alt={memory.title}
              className="w-full h-48 object-cover"
            />

            {/* Card Content */}
            <div className="p-5">

              {/* Category Tag */}
              <span className="inline-block bg-[#E0B84C] text-[#3A2A1A] text-xs px-3 py-1 rounded-full mb-3">
                {memory.category}
              </span>

              {/* Title */}
              <h2 className="text-xl font-serif text-[#8B2E1F] mb-2">
                {memory.title}
              </h2>

              {/* Description */}
              <p className="text-gray-600 text-sm mb-4">
                {memory.description}
              </p>

              {/* Location */}
              <p className="text-xs text-gray-500 mb-4">
                📍 {memory.location}
              </p>

              {/* Buttons */}
              <div className="flex justify-between items-center">

                <button className="text-[#8B2E1F] hover:text-[#6F2217] font-medium">
                  ❤️ Like
                </button>

                <button className="bg-[#8B2E1F] text-white px-4 py-1 rounded-lg hover:bg-[#6F2217] transition-all">
                  View
                </button>

              </div>
            </div>

          </motion.div>
        ))}

      </div>

      {/* If No Results Found */}
      {filteredMemories.length === 0 && (
        <div className="text-center mt-10 text-gray-600">
          No memories found.
        </div>
      )}

    </div>
  );
};

export default ExploreHeritage;
